import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Memuat Naik Log","description":"Cara memuat naik log untuk menyelesaikan masalah.","frontmatter":{"title":"Memuat Naik Log","description":"Cara memuat naik log untuk menyelesaikan masalah.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"ms_my/1.21.10/players/troubleshooting/uploading-logs.md","filePath":"versions/1.21.10/translated/ms_my/players/troubleshooting/uploading-logs.md","lastUpdated":1766682904000}`);var a={name:`ms_my/1.21.10/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Memuat Naik Log <a class="header-anchor" href="#h1" aria-label="Permalink to “Memuat Naik Log”">​</a></h1><p>Apabila menyelesaikan masalah, anda selalunya perlu menyediakan log untuk membantu mengenal pasti punca isu tersebut.</p><h2 id="mengapa-saya-perlu-memuat-naik-log" tabindex="-1">Mengapa saya perlu memuat naik log? <a class="header-anchor" href="#mengapa-saya-perlu-memuat-naik-log" aria-label="Permalink to “Mengapa saya perlu memuat naik log?”">​</a></h2><p>Memuat naik log membolehkan orang lain membantu anda dalam menyelesaikan masalah anda dengan lebih cepat daripada hanya menampal log ke dalam ruang perbualan atau siaran forum. Ia juga membolehkan anda berkongsi log anda dengan orang lain tanpa perlu menyalin dan menampalnya.</p><p>Sesetengah tapak penampalan juga menyediakan penyerlahan sintaks untuk log, yang menjadikannya lebih mudah dibaca dan mungkin menapis maklumat sensitif, seperti nama pengguna anda atau maklumat sistem.</p><h2 id="laporan-ranap-permainan" tabindex="-1">Laporan Ranap Permainan <a class="header-anchor" href="#laporan-ranap-permainan" aria-label="Permalink to “Laporan Ranap Permainan”">​</a></h2><p>Laporan ranap permainan dijana secara automatik apabila permainan ranap. Ia hanya mengandungi maklumat ranap dan bukan log sebenar permainan. Ia terletak di dalam folder <code>crash-reports</code> dalam direktori permainan.</p><p>Untuk mendapatkan maklumat lanjut tentang laporan ranap permainan, lihat <a href="./crash-reports">Laporan Ranap Permainan</a>.</p><h2 id="mencari-lokasi-log" tabindex="-1">Mencari Lokasi Log <a class="header-anchor" href="#mencari-lokasi-log" aria-label="Permalink to “Mencari Lokasi Log”">​</a></h2><p>Panduan ini merangkumi Pelancar Minecraft rasmi (biasanya dirujuk sebagai &quot;pelancar vanila&quot;) - untuk pelancar pihak ketiga, anda harus merujuk dokumentasi mereka.</p><p>Log-log terletak di dalam folder <code>log</code> dalam direktori permainan, direktori permainan boleh didapati di lokasi berikut bergantung pada sistem pengoperasian anda:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>Log terkini dipanggil <code>latest.log</code>, dan log sebelumnya menggunakan corak penamaan <code>yyyy-mm-dd_number.log.gz</code>.</p><h2 id="memuat-naik-log" tabindex="-1">Memuat Naik Log <a class="header-anchor" href="#memuat-naik-log" aria-label="Permalink to “Memuat Naik Log”">​</a></h2><p>Log boleh dimuat naik ke pelbagai perkhidmatan, seperti:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};